                   vartrans:translatableAs ?sicilianLexEntry .
    ?sicilianLexEntry ontolex:canonicalForm ?sicilianLemma .
    ?sicilianLemma dcterms:isPartOf <http://liita.it/data/id/DialettoSiciliano/lemma/LemmaBank> ;
