PREFIX dcterms: <http://purl.org/dc/terms/>
PREFIX elita: <http://w3id.org/elita/>
PREFIX lila: <http://lila-erc.eu/ontologies/lila/>
PREFIX lime: <http://www.w3.org/ns/lemon/lime#>
PREFIX marl: <http://www.gsi.upm.es/ontologies/marl/ns#>
PREFIX ontolex: <http://www.w3.org/ns/lemon/ontolex#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX vartrans: <http://www.w3.org/ns/lemon/vartrans#>
PREFIX lexinfo: <http://www.lexinfo.net/ontology/3.0/lexinfo#>

SELECT DISTINCT ?italianWord ?emotionLabel ?polarityValue ?parmigianoWord
WHERE {
    SERVICE <https://klab.ilc.cnr.it/graphdb-compl-it/> {
        ?piantaWord ontolex:canonicalForm [ ontolex:writtenRep ?piantaWr ] .
        FILTER(STR(?piantaWr) = "pianta")
        ?piantaWord ontolex:sense ?piantaSense .
        ?piantaSense lexinfo:hypernym ?hyponymSense .
        ?resultWord ontolex:sense ?hyponymSense .
    }

    ?resultWord ontolex:canonicalForm ?italianLemma .
    GRAPH <http://liita.it/data> {
        ?italianLemma a lila:Lemma ;
                      ontolex:writtenRep ?italianWord .
    }

    ?emotionEntry ontolex:canonicalForm ?italianLemma .
    GRAPH <http://w3id.org/elita> {
        ?emotionEntry elita:HasEmotion elita:Gioia .
        elita:Gioia rdfs:label ?emotionLabel .
    }

    ?polarityEntry ontolex:canonicalForm ?italianLemma ;
                   marl:hasPolarity ?polarity ;
                   marl:hasPolarityValue ?polarityValue .

    ?parmigianoEntry ontolex:canonicalForm ?italianLemma ;
                     vartrans:translatableAs ?parmigianoLexEntry .
    ?parmigianoLexEntry ^lime:entry <http://liita.it/data/id/LexicalReources/DialettoParmigiano/Lexicon> ;
                     ontolex:canonicalForm ?parmigianoLemma .
    ?parmigianoLemma ontolex:writtenRep ?parmigianoWord .
}
ORDER BY DESC(?polarityValue)
LIMIT 50

